#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
int m,d,n,ans,a[N],f[N][20];
int main(){
    scanf("%d%d",&m,&d);
    while(m--){
        char op;
        int x;
        cin>>op;
        scanf("%d",&x);
        if(op=='Q'){
            int mx=-2e9;
            for(int i=19,p=n;i>=0;i--)
                if(p-(1<<i)>=n-x)
                    mx=max(mx,f[p][i]),p-=(1<<i);
            ans=mx;
            printf("%d\n",mx);
        }
        if(op=='A'){
            n++;
            x=(1LL*x+ans)%d;
            a[n]=x;
            f[n][0]=a[n];
            for(int i=1;n-(1<<i)>=0;i++)
                f[n][i]=max(f[n][i-1],f[n-(1<<(i-1))][i-1]);
        }
    }
    return 0;
}
